// 8-Point Grid Responsive Spacing
BEGIN
 FUNCTION GetSpacing(size)
 // Size must be multiple of 8
 RETURN size * 8 // pixels
 END FUNCTION

 FUNCTION GetBreakpoints(device)
 SWITCH device
 CASE mobile:
 RETURN {min: 320, max: 767}
 CASE tablet:
 RETURN {min: 768, max: 1023}
 CASE desktop:
 RETURN {min: 1024, max: infinity}
 END SWITCH
 END FUNCTION

 // Common spacing values
 spacing = {
 xs: GetSpacing(1), // 8px
 sm: GetSpacing(2), // 16px
 md: GetSpacing(3), // 24px
 lg: GetSpacing(4), // 32px
 xl: GetSpacing(6) // 48px
 }
END
